import React, { useState, useEffect } from 'react';
import { AppState, Scene, Story } from './types';
import { generateStoryScript, generateNarration, generateCinematicImage } from './services/geminiService';
import { VideoPlayer } from './components/VideoPlayer';
import { Clapperboard, Sparkles, AlertCircle, Film, ArrowRight, Wand2, Clock } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [topic, setTopic] = useState('');
  const [duration, setDuration] = useState<number>(30);
  const [story, setStory] = useState<Story | null>(null);
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [progress, setProgress] = useState(0); // 0-100
  const [error, setError] = useState<string | null>(null);
  const [isApiKeySet, setIsApiKeySet] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async (): Promise<boolean> => {
    // Check if key is manually set in environment (e.g. .env file)
    if (process.env.API_KEY) {
      setIsApiKeySet(true);
      return true;
    }

    // Check AI Studio platform integration
    const aiStudio = (window as any).aistudio;
    if (aiStudio && await aiStudio.hasSelectedApiKey()) {
      setIsApiKeySet(true);
      return true;
    }

    setIsApiKeySet(false);
    return false;
  };

  const handleSelectKey = async () => {
    const aiStudio = (window as any).aistudio;
    if (aiStudio) {
      try {
        await aiStudio.openSelectKey();
      } catch (e) {
        console.error("Key selection cancelled or failed", e);
      }
      await checkApiKey();
    }
  };

  const handleGenerateStory = async () => {
    if (!topic.trim()) return;

    // Ensure key is available
    const hasKey = await checkApiKey();
    if (!hasKey) {
      await handleSelectKey();
      // Re-check after attempt
      const hasKeyAfterSelect = await checkApiKey();
      if (!hasKeyAfterSelect) return;
    }

    setAppState(AppState.SCRIPTING);
    setError(null);

    try {
      // Pass selected duration to the service
      const script = await generateStoryScript(topic, 'dramatic', duration);

      const initialScenes: Scene[] = script.scenes.map((s, i) => ({
        id: i,
        narration: s.narration,
        visualPrompt: s.visual_description,
        duration: 0,
        status: 'pending'
      }));

      setStory({
        title: script.title,
        scenes: initialScenes,
        musicMood: 'dramatic' // default
      });
      setScenes(initialScenes);

      // Start Asset Generation automatically
      generateAssets(initialScenes);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate story script";
      // Handle the case where the key is invalid or not found (common with some environments)
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("API key not valid")) {
        setIsApiKeySet(false);
        const aiStudio = (window as any).aistudio;
        if (aiStudio) {
            await aiStudio.openSelectKey();
            await checkApiKey();
        }
      }
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  const generateAssets = async (currentScenes: Scene[]) => {
    setAppState(AppState.GENERATING_ASSETS);
    const updatedScenes = [...currentScenes];
    const totalSteps = currentScenes.length * 2; // Audio + Visual per scene
    let completedSteps = 0;

    try {
      // 1. Generate Audio (Parallel) - Uses Gemini
      const audioPromises = updatedScenes.map(async (scene, index) => {
        try {
          const audioUrl = await generateNarration(scene.narration);
          updatedScenes[index].audioUrl = audioUrl;
          updatedScenes[index].status = 'loading'; // audio done, waiting for image
        } catch (err) {
          console.error(`Audio failed for scene ${index}`, err);
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
        }
      });

      await Promise.all(audioPromises);

      // 2. Generate Images (Sequential for safety, though Pollinations is free)
      for (let i = 0; i < updatedScenes.length; i++) {
        try {
          const visualUrl = await generateCinematicImage(updatedScenes[i].visualPrompt);
          updatedScenes[i].visualUrl = visualUrl;
          updatedScenes[i].status = 'complete';
        } catch (err) {
          console.error(`Image failed for scene ${i}`, err);
          updatedScenes[i].status = 'error';
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
          setScenes([...updatedScenes]); // Update UI
        }
      }

      setScenes(updatedScenes);
      setAppState(AppState.PREVIEW);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate assets. Please try again.";
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-indigo-500 selection:text-white">
      {/* Header */}
      <header className="fixed top-0 w-full z-50 border-b border-white/10 bg-black/80 backdrop-blur-md">
        <div className="max-w-5xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg flex items-center justify-center">
              <Clapperboard className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-xl tracking-tight">CineGen AI</span>
          </div>

          {!isApiKeySet && (
            <button 
                onClick={handleSelectKey}
                className="text-xs bg-zinc-800 hover:bg-zinc-700 px-3 py-1.5 rounded-full transition-colors border border-zinc-700"
            >
                Connect Gemini API
            </button>
          )}
        </div>
      </header>

      <main className="pt-24 pb-12 px-6 max-w-5xl mx-auto">

        {/* API Key Warning */}
        {!isApiKeySet && appState === AppState.IDLE && (
           <div className="mb-8 p-4 bg-yellow-500/10 border border-yellow-500/20 rounded-xl flex items-start gap-3">
             <AlertCircle className="w-5 h-5 text-yellow-500 shrink-0 mt-0.5" />
             <div>
               <h3 className="font-semibold text-yellow-500 text-sm mb-1">API Key Required</h3>
               <p className="text-zinc-400 text-sm">
                 To generate the story script and narration, you need to select a paid Google Cloud Project API key. 
                 <button onClick={handleSelectKey} className="text-yellow-500 hover:underline ml-1">Select Key</button>
               </p>
             </div>
           </div>
        )}

        {/* Input Phase */}
        {appState === AppState.IDLE && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
             <div className="space-y-4 max-w-2xl">
                <h1 className="text-5xl md:text-6xl font-extrabold tracking-tighter text-transparent bg-clip-text bg-gradient-to-b from-white to-white/40">
                  Turn ideas into movies.
                </h1>
                <p className="text-lg text-zinc-400">
                  Enter a prompt, and AI will write the script, voice the characters, and film the scenes.
                </p>
             </div>

             <div className="w-full max-w-md space-y-4">
               {/* Prompt Input */}
               <div className="relative group">
                 <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-xl opacity-75 group-hover:opacity-100 blur transition duration-200"></div>
                 <div className="relative flex bg-black rounded-xl p-1">
                   <input 
                      type="text" 
                      value={topic}
                      onChange={(e) => setTopic(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleGenerateStory()}
                      placeholder="E.g., A cyberpunk detective in 2099..."
                      className="w-full bg-transparent text-white placeholder-zinc-500 px-4 py-3 outline-none"
                   />
                   <button 
                      onClick={handleGenerateStory}
                      disabled={!topic.trim()}
                      className="bg-zinc-900 hover:bg-zinc-800 text-white p-3 rounded-lg transition-colors border border-zinc-800"
                   >
                      <ArrowRight className="w-5 h-5" />
                   </button>
                 </div>
               </div>

               {/* Duration Selector */}
               <div className="flex justify-center gap-2">
                  {[15, 30, 60].map((s) => (
                    <button
                      key={s}
                      onClick={() => setDuration(s)}
                      className={`
                        flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-medium border transition-all
                        ${duration === s 
                          ? 'bg-zinc-100 text-black border-zinc-100' 
                          : 'bg-zinc-900/50 text-zinc-400 border-zinc-800 hover:border-zinc-700 hover:text-white'
                        }
                      `}
                    >
                      <Clock className="w-3 h-3" />
                      {s}s {s === 15 ? '(Short)' : s === 30 ? '(Medium)' : '(Long)'}
                    </button>
                  ))}
               </div>
             </div>

             <div className="flex gap-4 text-sm text-zinc-500">
               <span className="flex items-center gap-1"><Sparkles className="w-3 h-3" /> Gemini 2.5 Flash Scripting</span>
               <span className="flex items-center gap-1"><Film className="w-3 h-3" /> Pollinations.ai Visuals</span>
             </div>
          </div>
        )}

        {/* Loading Phase */}
        {(appState === AppState.SCRIPTING || appState === AppState.GENERATING_ASSETS) && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8">
            <div className="relative w-24 h-24">
               <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
               <div 
                  className="absolute inset-0 border-4 border-indigo-500 rounded-full border-t-transparent animate-spin"
               ></div>
               <div className="absolute inset-0 flex items-center justify-center">
                 <Wand2 className="w-8 h-8 text-indigo-400 animate-pulse" />
               </div>
            </div>

            <div className="text-center space-y-2">
              <h2 className="text-2xl font-bold">
                {appState === AppState.SCRIPTING ? 'Writing the Script...' : 'Filming Scenes...'}
              </h2>
              <p className="text-zinc-400">
                {appState === AppState.SCRIPTING 
                  ? `Crafting a ${duration} second story in Kannada...` 
                  : `Generating AI assets: ${Math.round(progress)}%`
                }
              </p>
            </div>

            {appState === AppState.GENERATING_ASSETS && (
              <div className="w-full max-w-md space-y-3">
                 {scenes.map((scene) => (
                    <div key={scene.id} className="flex items-center gap-3 text-sm">
                      <div className={`w-2 h-2 rounded-full ${
                        scene.status === 'complete' ? 'bg-green-500' : 
                        scene.status === 'loading' ? 'bg-yellow-500 animate-pulse' : 
                        scene.status === 'error' ? 'bg-red-500' : 'bg-zinc-700'
                      }`} />
                      <span className={`flex-1 truncate ${scene.status === 'pending' ? 'text-zinc-600' : 'text-zinc-300'}`}>
                        Scene {scene.id + 1}: {scene.narration}
                      </span>
                    </div>
                 ))}
              </div>
            )}
          </div>
        )}

        {/* Editor/Preview Phase */}
        {appState === AppState.PREVIEW && story && (
           <div className="animate-in fade-in duration-500 flex flex-col md:flex-row gap-8 items-start justify-center">

              {/* Video Player Section */}
              <div className="w-full md:w-auto md:flex-1 flex justify-center sticky top-24">
                <VideoPlayer 
                  scenes={scenes} 
                  appState={appState}
                  musicMood={story.musicMood}
                  onReset={() => {
                    setAppState(AppState.IDLE);
                    setTopic('');
                    setScenes([]);
                    setStory(null);
                  }}
                />
              </div>

              {/* Story Details (Sidebar) */}
              <div className="w-full md:w-80 lg:w-96 space-y-6">
                <div>
                  <h2 className="text-2xl font-bold mb-2">{story.title}</h2>
                  <div className="flex items-center gap-2 text-zinc-400 text-sm">
                    <span className="capitalize px-2 py-0.5 rounded bg-zinc-800 border border-zinc-700">{story.musicMood}</span>
                    <span>• {scenes.length} Scenes</span>
                    <span>• ~{duration}s</span>
                  </div>
                </div>

                <div className="space-y-4">
                  <h3 className="text-sm font-semibold text-zinc-500 uppercase tracking-wider">Script</h3>
                  {scenes.map((scene, i) => (
                    <div key={i} className="p-4 rounded-lg bg-zinc-900 border border-zinc-800 hover:border-zinc-700 transition-colors">
                      <div className="flex justify-between items-start mb-2">
                        <span className="text-xs font-mono text-indigo-400">SCENE {i + 1}</span>
                      </div>
                      <p className="text-zinc-300 text-sm mb-3 leading-relaxed">"{scene.narration}"</p>

                      <div className="relative rounded-md overflow-hidden aspect-video bg-black">
                        {scene.visualUrl ? (
                          <img src={scene.visualUrl} alt="Scene preview" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition-opacity" />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-zinc-700 text-xs">No Visual</div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

           </div>
        )}

        {error && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-red-500/10 border border-red-500 text-red-500 px-6 py-4 rounded-lg backdrop-blur-md shadow-xl flex items-center gap-3 z-50">
             <AlertCircle className="w-5 h-5" />
             <span>{error}</span>
             <button onClick={() => setAppState(AppState.IDLE)} className="ml-4 text-white bg-red-600 hover:bg-red-700 px-3 py-1 rounded text-sm">Dismiss</button>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Scene, AppState } from '../types';
import { Play, Pause, Download, RefreshCw, Loader2 } from 'lucide-react';

interface VideoPlayerProps {
  scenes: Scene[];
  appState: AppState;
  musicMood: string;
  onReset: () => void;
}

const VIDEO_WIDTH = 1080 / 2; // Scaled down for preview, exported at full res logic
const VIDEO_HEIGHT = 1920 / 2;

// Background music placeholder URLs (Royalty Free / CC0 for demo)
const MUSIC_URLS: Record<string, string> = {
  dramatic: 'https://cdn.pixabay.com/download/audio/2022/03/10/audio_5b66415712.mp3', // Epic Cinematic
  cheerful: 'https://cdn.pixabay.com/download/audio/2022/10/25/audio_547161833d.mp3', // Happy Day
  mysterious: 'https://cdn.pixabay.com/download/audio/2022/02/07/audio_6512133497.mp3', // Investigation
  energetic: 'https://cdn.pixabay.com/download/audio/2023/06/13/audio_496c8104e1.mp3'  // Action
};

export const VideoPlayer: React.FC<VideoPlayerProps> = ({ scenes, appState, musicMood, onReset }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);
  const [isExporting, setIsExporting] = useState(false);

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const bgMusicNodeRef = useRef<HTMLAudioElement | null>(null);
  const narrationNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const destNodeRef = useRef<MediaStreamAudioDestinationNode | null>(null);

  // Animation Refs
  const reqIdRef = useRef<number>(0);
  const startTimeRef = useRef<number>(0);
  const sceneImagesRef = useRef<Record<number, HTMLImageElement>>({});
  const sceneAudioBuffersRef = useRef<Record<number, AudioBuffer>>({});

  // Preload Assets
  useEffect(() => {
    if (appState !== AppState.PREVIEW) return;

    const loadAssets = async () => {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = audioCtx;

      // Load Images and Audio
      const images: Record<number, HTMLImageElement> = {};
      const buffers: Record<number, AudioBuffer> = {};
      let totalTime = 0;

      for (const scene of scenes) {
        // Image
        if (scene.visualUrl) {
          try {
            const img = new Image();
            img.crossOrigin = "anonymous"; // Safety for cross-origin if needed
            img.src = scene.visualUrl;
            await new Promise((r, j) => {
                img.onload = r;
                img.onerror = j;
            }).catch(e => console.warn(`Failed to load image for scene ${scene.id}`, e));
            images[scene.id] = img;
          } catch (e) {
             console.error("Image load error", e);
          }
        }

        // Audio
        let sceneDur = 5; // Default fallback
        if (scene.audioUrl) {
          try {
            const resp = await fetch(scene.audioUrl);
            const arrayBuffer = await resp.arrayBuffer();
            // Wrap in try-catch as decoding is strict
            const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);
            buffers[scene.id] = audioBuffer;
            sceneDur = audioBuffer.duration + 0.5; // add tiny padding
          } catch (e) {
            console.error(`Failed to decode audio for scene ${scene.id}.`, e);
            // Fallback: Estimate based on word count (rough approx)
            sceneDur = Math.max(3, scene.narration.split(' ').length * 0.4);
          }
        } else {
             sceneDur = Math.max(3, scene.narration.split(' ').length * 0.4);
        }

        scene.duration = sceneDur;
        totalTime += sceneDur;
      }

      sceneImagesRef.current = images;
      sceneAudioBuffersRef.current = buffers;
      setTotalDuration(totalTime);
    };

    loadAssets();

    return () => {
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, [scenes, appState]);

  // Render Loop
  const renderFrame = useCallback((timestamp: number) => {
    if (!startTimeRef.current) startTimeRef.current = timestamp;
    const elapsed = (timestamp - startTimeRef.current) / 1000; // in seconds

    // Looping logic or stopping
    if (elapsed >= totalDuration) {
      if (isExporting) {
        // Let the export logic handle stop
      } else {
        setIsPlaying(false);
        setCurrentTime(totalDuration);
        stopAudio();
      }
      return; 
    }

    setCurrentTime(elapsed);

    // Find current scene
    let accumulatedTime = 0;
    let currentScene = scenes[0];
    let sceneStartTime = 0;

    for (const scene of scenes) {
      if (elapsed < accumulatedTime + scene.duration) {
        currentScene = scene;
        sceneStartTime = accumulatedTime;
        break;
      }
      accumulatedTime += scene.duration;
    }

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');

    // Use the loaded image or fallback
    const img = sceneImagesRef.current[currentScene.id];

    if (canvas && ctx) {
      // Clear
      ctx.fillStyle = '#000';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      if (img) {
        // Ken Burns Effect logic
        const sceneProgress = (elapsed - sceneStartTime) / currentScene.duration;
        const scale = 1 + (sceneProgress * 0.15); // Zoom in 15%

        // Calculate center position
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;

        ctx.save();
        ctx.translate(centerX, centerY);
        ctx.scale(scale, scale);

        // Slight pan based on scene ID (odd/even)
        const panX = (currentScene.id % 2 === 0 ? 1 : -1) * (sceneProgress * 50);
        ctx.translate(-centerX + panX, -centerY);

        // Draw image cover
        const imgRatio = img.width / img.height;
        const canvasRatio = canvas.width / canvas.height;
        let renderW, renderH;

        if (imgRatio > canvasRatio) {
            renderH = canvas.height;
            renderW = img.width * (canvas.height / img.height);
        } else {
            renderW = canvas.width;
            renderH = img.height * (canvas.width / img.width);
        }

        const drawX = (canvas.width - renderW) / 2;
        const drawY = (canvas.height - renderH) / 2;

        ctx.drawImage(img, drawX, drawY, renderW, renderH);
        ctx.restore();
      } else {
        // No Image Placeholder
        ctx.fillStyle = '#18181b';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#52525b';
        ctx.font = '20px Inter';
        ctx.textAlign = 'center';
        ctx.fillText("Visual Generating or Failed", canvas.width / 2, canvas.height / 2);
      }

      // Draw Subtitles
      // IMPORTANT: Use Noto Sans Kannada for correct rendering
      ctx.font = 'bold 24px "Noto Sans Kannada", Inter, sans-serif';
      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.textAlign = 'center';

      const maxWidth = canvas.width * 0.8;
      const words = currentScene.narration.split(' ');
      let line = '';
      let y = canvas.height - 150;

      ctx.fillStyle = 'white';
      ctx.shadowColor = 'black';
      ctx.shadowBlur = 4;

      for(let n = 0; n < words.length; n++) {
        const testLine = line + words[n] + ' ';
        const metrics = ctx.measureText(testLine);
        const testWidth = metrics.width;
        if (testWidth > maxWidth && n > 0) {
          ctx.fillText(line, canvas.width/2, y);
          line = words[n] + ' ';
          y += 35;
        } else {
          line = testLine;
        }
      }
      ctx.fillText(line, canvas.width/2, y);
      ctx.shadowBlur = 0;
    }

    if (isPlaying || isExporting) {
        reqIdRef.current = requestAnimationFrame(renderFrame);
    }
  }, [scenes, totalDuration, isPlaying, isExporting]);

  useEffect(() => {
    if (isPlaying && !isExporting) {
       playAudioSequence(currentTime);
       reqIdRef.current = requestAnimationFrame(renderFrame);
    } else if (!isPlaying && !isExporting) {
       cancelAnimationFrame(reqIdRef.current);
       stopAudio();
    }
  }, [isPlaying, renderFrame]);


  const playAudioSequence = async (startOffset: number) => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;

    // Stop previous
    stopAudio();

    // 1. Play Background Music
    const musicUrl = MUSIC_URLS[musicMood] || MUSIC_URLS['dramatic'];
    const bgAudio = new Audio(musicUrl);
    bgAudio.loop = true;
    bgAudio.volume = 0.3;
    bgAudio.currentTime = startOffset % 100; // rough seek
    bgAudio.play().catch(e => console.log("Auto-play prevented", e));
    bgMusicNodeRef.current = bgAudio;

    // 2. Schedule Voiceovers
    // We need to figure out which scene we are in and schedule remaining scenes
    let accumulatedTime = 0;
    scenes.forEach((scene) => {
        const buffer = sceneAudioBuffersRef.current[scene.id];
        if (buffer) {
            const playTime = ctx.currentTime + (accumulatedTime - startOffset);

            // Only schedule if it's in the future or currently playing
            if (accumulatedTime + scene.duration > startOffset) {
                const source = ctx.createBufferSource();
                source.buffer = buffer;
                source.connect(ctx.destination);

                // If we are mid-scene, we need to offset the start
                let offset = 0;
                let actualStartTime = playTime;

                if (accumulatedTime < startOffset) {
                    offset = startOffset - accumulatedTime;
                    actualStartTime = ctx.currentTime;
                }

                source.start(actualStartTime, offset);
                // Track current playing node (imperfect for multiple, but good enough for stop)
                narrationNodeRef.current = source;
            }
        }
        accumulatedTime += scene.duration;
    });
  };

  const stopAudio = () => {
    if (bgMusicNodeRef.current) {
        bgMusicNodeRef.current.pause();
        bgMusicNodeRef.current = null;
    }
    if (narrationNodeRef.current) {
        try { narrationNodeRef.current.stop(); } catch(e) {}
        narrationNodeRef.current = null;
    }
  };

  const handleExport = async () => {
    if (!canvasRef.current || !audioContextRef.current) return;
    setIsExporting(true);
    setIsPlaying(true);
    setCurrentTime(0);
    startTimeRef.current = 0; // Reset for render loop logic

    const stream = canvasRef.current.captureStream(30); // 30 FPS
    const audioCtx = audioContextRef.current;
    const dest = audioCtx.createMediaStreamDestination();
    destNodeRef.current = dest;

    // Setup Mix for recording
    // 1. Voice Mix
    let accumulatedTime = 0;
    const sources: AudioBufferSourceNode[] = [];

    scenes.forEach((scene) => {
        const buffer = sceneAudioBuffersRef.current[scene.id];
        if (buffer) {
            const source = audioCtx.createBufferSource();
            source.buffer = buffer;
            source.connect(dest); // Connect to recorder destination
            source.connect(audioCtx.destination); // Also connect to speakers to hear it
            source.start(audioCtx.currentTime + accumulatedTime);
            sources.push(source);
        }
        accumulatedTime += scene.duration;
    });

    // 2. BG Music Mix
    try {
        const musicUrl = MUSIC_URLS[musicMood] || MUSIC_URLS['dramatic'];
        const bgResp = await fetch(musicUrl);
        const bgArr = await bgResp.arrayBuffer();
        const bgBuff = await audioCtx.decodeAudioData(bgArr);

        const bgSource = audioCtx.createBufferSource();
        bgSource.buffer = bgBuff;
        bgSource.loop = true;
        const bgGain = audioCtx.createGain();
        bgGain.gain.value = 0.3;
        bgSource.connect(bgGain);
        bgGain.connect(dest);
        bgGain.connect(audioCtx.destination);
        bgSource.start(audioCtx.currentTime);
    } catch (e) {
        console.warn("Background music failed to load for export", e);
    }

    // Add audio track to canvas stream
    if (dest.stream.getAudioTracks().length > 0) {
        stream.addTrack(dest.stream.getAudioTracks()[0]);
    }

    // DETERMINE FORMAT: Prefer MP4, fallback to WebM
    let mimeType = 'video/webm';
    let fileExtension = 'webm';

    if (MediaRecorder.isTypeSupported('video/mp4')) {
      mimeType = 'video/mp4';
      fileExtension = 'mp4';
    } else if (MediaRecorder.isTypeSupported('video/webm;codecs=h264')) {
       // Chrome/Edge often support this
       mimeType = 'video/webm;codecs=h264';
       fileExtension = 'mp4'; // HACK: Some players treat H264 inside WebM container as MP4 if renamed, or just keep webm.
    }

    console.log(`Exporting using MIME: ${mimeType}`);

    const recorder = new MediaRecorder(stream, { mimeType });

    const chunks: Blob[] = [];
    recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
    };

    recorder.onstop = () => {
        const blob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `CineGen_${Date.now()}.${fileExtension}`;
        a.click();

        // Cleanup
        setIsExporting(false);
        setIsPlaying(false);
        sources.forEach(s => { try { s.stop(); } catch(e){} });
    };

    recorder.start();

    // Start Rendering loop
    startTimeRef.current = performance.now();
    reqIdRef.current = requestAnimationFrame(function exportLoop(timestamp) {
         // Custom render loop just for export to ensure we don't depend on React state updates for 'currentTime'
         // We simulate the time
         const exportElapsed = (timestamp - startTimeRef.current) / 1000;

         // Update visual state (reuse render logic logic partially or duplicate for safety)
         renderFrame(timestamp);

         if (exportElapsed < totalDuration) {
             reqIdRef.current = requestAnimationFrame(exportLoop);
         } else {
             recorder.stop();
         }
    });
  };

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-lg mx-auto bg-zinc-900 rounded-xl overflow-hidden shadow-2xl border border-zinc-800">
      <div className="relative w-full aspect-[9/16] bg-black">
        <canvas
          ref={canvasRef}
          width={540} // Internal resolution (rendering 1080p in canvas is heavy for preview, usually scale down)
          height={960}
          className="w-full h-full object-cover"
        />

        {/* Overlays */}
        {!isPlaying && !isExporting && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-10">
                <button 
                    onClick={() => { startTimeRef.current = 0; setIsPlaying(true); }}
                    className="p-6 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-md border border-white/30 group"
                >
                    <Play className="w-12 h-12 text-white fill-current group-hover:scale-110 transition-transform" />
                </button>
            </div>
        )}

        {isExporting && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 z-20">
                <Loader2 className="w-12 h-12 text-indigo-500 animate-spin mb-4" />
                <p className="text-white font-medium">Rendering Video...</p>
                <p className="text-zinc-400 text-sm">Please wait, do not close tab.</p>
            </div>
        )}
      </div>

      <div className="w-full p-4 bg-zinc-900 border-t border-zinc-800">
        <div className="flex items-center justify-between mb-2">
            <span className="text-xs text-zinc-500 font-mono">
                {Math.floor(currentTime)}s / {Math.floor(totalDuration)}s
            </span>
            <div className="flex gap-2">
                 <button
                    disabled={isExporting} 
                    onClick={onReset}
                    className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-zinc-400 hover:text-white transition-colors"
                >
                    <RefreshCw className="w-3 h-3" />
                    New Story
                </button>
                <button 
                    onClick={handleExport}
                    disabled={isExporting}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white rounded-lg text-sm font-semibold transition-all"
                >
                    {isExporting ? 'Exporting...' : 'Export Video'}
                    {!isExporting && <Download className="w-4 h-4" />}
                </button>
            </div>
        </div>

        {/* Progress Bar */}
        <div className="w-full h-1.5 bg-zinc-800 rounded-full overflow-hidden">
            <div 
                className="h-full bg-indigo-500 transition-all duration-100 ease-linear"
                style={{ width: `${(currentTime / (totalDuration || 1)) * 100}%` }}
            />
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ScriptResponse, Scene } from "../types";

// Helper to get client with current key
const getClient = () => {
  // Always create a new instance to ensure we capture the latest key from aistudio
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// --- WAV Header Helpers ---
// Gemini TTS returns raw PCM (24kHz, 1 channel, 16-bit). We need to wrap it in a WAV header for browser compatibility.
const writeString = (view: DataView, offset: number, string: string) => {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
};

const addWavHeader = (samples: Uint8Array, sampleRate: number = 24000, numChannels: number = 1) => {
  const buffer = new ArrayBuffer(44 + samples.length);
  const view = new DataView(buffer);

  // RIFF identifier
  writeString(view, 0, 'RIFF');
  // file length
  view.setUint32(4, 36 + samples.length, true);
  // RIFF type
  writeString(view, 8, 'WAVE');
  // format chunk identifier
  writeString(view, 12, 'fmt ');
  // format chunk length
  view.setUint32(16, 16, true);
  // sample format (1 is PCM)
  view.setUint16(20, 1, true);
  // channel count
  view.setUint16(22, numChannels, true);
  // sample rate
  view.setUint32(24, sampleRate, true);
  // byte rate (sample rate * block align)
  view.setUint32(28, sampleRate * numChannels * 2, true);
  // block align (channel count * bytes per sample)
  view.setUint16(32, numChannels * 2, true);
  // bits per sample
  view.setUint16(34, 16, true);
  // data chunk identifier
  writeString(view, 36, 'data');
  // data chunk length
  view.setUint32(40, samples.length, true);

  // write the PCM samples
  const pcmBytes = new Uint8Array(buffer, 44);
  pcmBytes.set(samples);

  return buffer;
};

