export const generateStoryScript = async (topic: string, mood: string, duration: number = 30): Promise<ScriptResponse> => {
  const ai = getClient();

  // Calculate approx scenes based on duration (avg 5-6 seconds per scene)
  // 15s -> 3 scenes
  // 30s -> 5 scenes
  // 60s -> 10 scenes
  const numScenes = Math.max(3, Math.ceil(duration / 6));

  const prompt = `
    You are a world-class cinematographer and screenwriter. 
    Write a short, engaging, cinematic story based on the topic: "${topic}".
    The mood is: ${mood}.

    Target Duration: Approximately ${duration} seconds.
    Structure the story into exactly ${numScenes} distinct scenes.

    For each scene, provide:
    1. 'narration': The spoken voiceover text in Kannada language (Kannada script). Keep it punchy, emotional, and human.
    2. 'visual_description': A highly detailed, photorealistic AI image prompt describing the scene in English. Include camera angles (Wide shot, Close up, Low angle), lighting (Golden hour, Neon, Cinematic lighting), and action.

    Return the response strictly as JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                narration: { type: Type.STRING },
                visual_description: { type: Type.STRING },
              },
              required: ["narration", "visual_description"]
            }
          }
        },
        required: ["title", "scenes"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No script generated");
  return JSON.parse(text) as ScriptResponse;
};

export const generateNarration = async (text: string, voiceName: string = 'Fenrir'): Promise<string> => {
  const ai = getClient();

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: {
      parts: [{ text: text }]
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voiceName }
        }
      }
    }
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  // Convert base64 to binary
  const binaryString = window.atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // WRAP IN WAV HEADER (Critical fix for "Unable to decode audio data")
  const wavBuffer = addWavHeader(bytes);
  const blob = new Blob([wavBuffer], { type: "audio/wav" });

  return URL.createObjectURL(blob);
};

export const generateCinematicImage = async (prompt: string): Promise<string> => {
  // Use Pollinations.ai for free unlimited image generation
  const seed = Math.floor(Math.random() * 10000000);

  // Clean prompt and limit length to ensure URL safety and API limits
  const safePrompt = prompt.replace(/[^\w\s,.-]/g, '').slice(0, 800);
  const enhancedPrompt = encodeURIComponent(`Cinematic vertical shot 9:16 aspect ratio ${safePrompt} high detail 8k photorealistic`);

  // Use 720x1280 (720p Vertical) instead of 1080x1920
  // Higher resolutions often cause timeouts or errors on the free tier
  const width = 720;
  const height = 1280;

  const url = `https://image.pollinations.ai/prompt/${enhancedPrompt}?width=${width}&height=${height}&model=flux&seed=${seed}&nologo=true`;

  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Pollinations API Error: ${response.status} ${response.statusText}`);
    }
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error) {
    console.error("Pollinations Image Generation Failed:", error);
    // If flux fails, could fallback, but usually it's just a transient glitch or size issue.
    // Throwing so UI shows error state.
    throw error;
  }
};

