                    <div key={scene.id} className="flex items-center gap-3 text-sm">
                      <div className={`w-2 h-2 rounded-full ${
                        scene.status === 'complete' ? 'bg-green-500' : 
                        scene.status === 'loading' ? 'bg-yellow-500 animate-pulse' : 
                        scene.status === 'error' ? 'bg-red-500' : 'bg-zinc-700'
                      }`} />
                      <span className={`flex-1 truncate ${scene.status === 'pending' ? 'text-zinc-600' : 'text-zinc-300'}`}>
                        Scene {scene.id + 1}: {scene.narration}
                      </span>
                    </div>
                 ))}
              </div>
            )}
          </div>
        )}

        {/* Editor/Preview Phase */}
        {appState === AppState.PREVIEW && story && (
           <div className="animate-in fade-in duration-500 flex flex-col md:flex-row gap-8 items-start justify-center">

              {/* Video Player Section */}
              <div className="w-full md:w-auto md:flex-1 flex justify-center sticky top-24">
                <VideoPlayer 
                  scenes={scenes} 
                  appState={appState}
                  musicMood={story.musicMood}
                  onReset={() => {
                    setAppState(AppState.IDLE);
                    setTopic('');
                    setScenes([]);
                    setStory(null);
                  }}
                />
              </div>

              {/* Story Details (Sidebar) */}
              <div className="w-full md:w-80 lg:w-96 space-y-6">
                <div>
                  <h2 className="text-2xl font-bold mb-2">{story.title}</h2>
                  <div className="flex items-center gap-2 text-zinc-400 text-sm">
                    <span className="capitalize px-2 py-0.5 rounded bg-zinc-800 border border-zinc-700">{story.musicMood}</span>
                    <span>• {scenes.length} Scenes</span>
                    <span>• ~{duration}s</span>
                  </div>
                </div>

                <div className="space-y-4">
                  <h3 className="text-sm font-semibold text-zinc-500 uppercase tracking-wider">Script</h3>
                  {scenes.map((scene, i) => (
                    <div key={i} className="p-4 rounded-lg bg-zinc-900 border border-zinc-800 hover:border-zinc-700 transition-colors">
                      <div className="flex justify-between items-start mb-2">
                        <span className="text-xs font-mono text-indigo-400">SCENE {i + 1}</span>
                      </div>
                      <p className="text-zinc-300 text-sm mb-3 leading-relaxed">"{scene.narration}"</p>

                      <div className="relative rounded-md overflow-hidden aspect-video bg-black">
                        {scene.visualUrl ? (
                          <img src={scene.visualUrl} alt="Scene preview" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition-opacity" />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-zinc-700 text-xs">No Visual</div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

           </div>
        )}

        {error && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-red-500/10 border border-red-500 text-red-500 px-6 py-4 rounded-lg backdrop-blur-md shadow-xl flex items-center gap-3 z-50">
             <AlertCircle className="w-5 h-5" />
             <span>{error}</span>
             <button onClick={() => setAppState(AppState.IDLE)} className="ml-4 text-white bg-red-600 hover:bg-red-700 px-3 py-1 rounded text-sm">Dismiss</button>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AppState, Scene, Story, UsageStats } from './types';
import { generateStoryScript, generateNarration, generateCinematicImage } from './services/geminiService';
import { VideoPlayer } from './components/VideoPlayer';
import { Clapperboard, Sparkles, AlertCircle, Film, ArrowRight, Wand2, Clock, Activity, X, Calculator, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [topic, setTopic] = useState('');
  const [duration, setDuration] = useState<number>(30);
  const [story, setStory] = useState<Story | null>(null);
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [progress, setProgress] = useState(0); // 0-100
  const [error, setError] = useState<string | null>(null);
  const [isApiKeySet, setIsApiKeySet] = useState(false);

  // Usage Tracking State
  const [stats, setStats] = useState<UsageStats>({ scriptsGenerated: 0, audioGenerated: 0, imagesGenerated: 0 });
  const [showStats, setShowStats] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async (): Promise<boolean> => {
    // Check if key is manually set in environment (e.g. .env file)
    if (process.env.API_KEY) {
      setIsApiKeySet(true);
      return true;
    }

    // Check AI Studio platform integration
    const aiStudio = (window as any).aistudio;
    if (aiStudio && await aiStudio.hasSelectedApiKey()) {
      setIsApiKeySet(true);
      return true;
    }

    setIsApiKeySet(false);
    return false;
  };

  const handleSelectKey = async () => {
    const aiStudio = (window as any).aistudio;
    if (aiStudio) {
      try {
        await aiStudio.openSelectKey();
      } catch (e) {
        console.error("Key selection cancelled or failed", e);
      }
      await checkApiKey();
    }
  };

  const handleGenerateStory = async () => {
    if (!topic.trim()) return;

    // Ensure key is available
    const hasKey = await checkApiKey();
    if (!hasKey) {
      await handleSelectKey();
      // Re-check after attempt
      const hasKeyAfterSelect = await checkApiKey();
      if (!hasKeyAfterSelect) return;
    }

    setAppState(AppState.SCRIPTING);
    setError(null);

    try {
      // Pass selected duration to the service
      const script = await generateStoryScript(topic, 'dramatic', duration);

      // Update Stats
      setStats(prev => ({ ...prev, scriptsGenerated: prev.scriptsGenerated + 1 }));

      const initialScenes: Scene[] = script.scenes.map((s, i) => ({
        id: i,
        narration: s.narration,
        visualPrompt: s.visual_description,
        duration: 0,
        status: 'pending'
      }));

      setStory({
        title: script.title,
        scenes: initialScenes,
        musicMood: 'dramatic' // default
      });
      setScenes(initialScenes);

      // Start Asset Generation automatically
      generateAssets(initialScenes);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate story script";
      // Handle the case where the key is invalid or not found (common with some environments)
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("API key not valid")) {
        setIsApiKeySet(false);
        const aiStudio = (window as any).aistudio;
        if (aiStudio) {
            await aiStudio.openSelectKey();
            await checkApiKey();
        }
      }
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  const generateAssets = async (currentScenes: Scene[]) => {
    setAppState(AppState.GENERATING_ASSETS);
    const updatedScenes = [...currentScenes];
    const totalSteps = currentScenes.length * 2; // Audio + Visual per scene
    let completedSteps = 0;

    try {
      // 1. Generate Audio (Parallel) - Uses Gemini
      const audioPromises = updatedScenes.map(async (scene, index) => {
        try {
          const audioUrl = await generateNarration(scene.narration);
          updatedScenes[index].audioUrl = audioUrl;
          updatedScenes[index].status = 'loading'; // audio done, waiting for image

          // Update Stats
          setStats(prev => ({ ...prev, audioGenerated: prev.audioGenerated + 1 }));

        } catch (err) {
          console.error(`Audio failed for scene ${index}`, err);
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
        }
      });

      await Promise.all(audioPromises);

      // 2. Generate Images (Sequential for safety, though Pollinations is free)
      for (let i = 0; i < updatedScenes.length; i++) {
        try {
          const visualUrl = await generateCinematicImage(updatedScenes[i].visualPrompt);
          updatedScenes[i].visualUrl = visualUrl;
          updatedScenes[i].status = 'complete';

          // Update Stats
          setStats(prev => ({ ...prev, imagesGenerated: prev.imagesGenerated + 1 }));

        } catch (err) {
          console.error(`Image failed for scene ${i}`, err);
          updatedScenes[i].status = 'error';
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
          setScenes([...updatedScenes]); // Update UI
        }
      }

      setScenes(updatedScenes);
      setAppState(AppState.PREVIEW);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate assets. Please try again.";
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  // Calculate Estimates
  const estimatedScenes = Math.max(3, Math.ceil(duration / 6));
  // Rough calculation: 5s script + 3s audio batch + (4s per image * numScenes)
  const estimatedTime = 5 + 3 + (estimatedScenes * 4);

  return (
    <div className="min-h-screen bg-black text-white selection:bg-indigo-500 selection:text-white">
      {/* Header */}
      <header className="fixed top-0 w-full z-50 border-b border-white/10 bg-black/80 backdrop-blur-md">
        <div className="max-w-5xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { setAppState(AppState.IDLE); setStory(null); setScenes([]); setTopic(''); }}>
            <div className="w-8 h-8 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg flex items-center justify-center">
              <Clapperboard className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-xl tracking-tight">CineGen AI</span>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => setShowStats(true)}
                className="flex items-center gap-1.5 text-xs bg-zinc-900 hover:bg-zinc-800 px-3 py-1.5 rounded-full transition-colors border border-zinc-800 text-zinc-400 hover:text-white"
             >
                <Activity className="w-3.5 h-3.5" />
                <span>Usage</span>
             </button>

            {!isApiKeySet && (
                <button 
                    onClick={handleSelectKey}
                    className="text-xs bg-indigo-600 hover:bg-indigo-500 px-3 py-1.5 rounded-full transition-colors font-medium"
                >
                    Connect Gemini API
                </button>
            )}
          </div>
        </div>
      </header>

      {/* Stats Modal */}
      {showStats && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="bg-zinc-900 border border-zinc-800 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden">
              <div className="p-6 border-b border-zinc-800 flex justify-between items-center">
                 <div className="flex items-center gap-2">
                    <Activity className="w-5 h-5 text-indigo-500" />
                    <h2 className="font-bold text-lg">API Usage & Limits</h2>
                 </div>
                 <button onClick={() => setShowStats(false)} className="text-zinc-500 hover:text-white transition-colors">
                    <X className="w-5 h-5" />
                 </button>
              </div>

              <div className="p-6 space-y-6">
                 {/* Scripting Stats */}
                 <div className="space-y-2">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <Sparkles className="w-4 h-4 text-purple-400" />
                            <span className="font-medium">Scripting (Gemini 2.5 Flash)</span>
                        </div>
                        <span className="bg-zinc-800 px-2 py-0.5 rounded text-xs font-mono text-white">{stats.scriptsGenerated} Calls</span>
                    </div>
                    <div className="text-xs text-zinc-500 bg-zinc-950/50 p-3 rounded-lg border border-zinc-800/50">
                        <p className="font-semibold text-zinc-400 mb-1">Rate Limits:</p>
                        <ul className="list-disc list-inside space-y-1">
                            <li><strong>Free Tier:</strong> 15 RPM (Requests Per Min), 1,500 RPD (Requests Per Day).</li>
                            <li><strong>Paid Tier:</strong> 1,000 RPM.</li>
                        </ul>
                    </div>
                 </div>

                 {/* Audio Stats */}
                 <div className="space-y-2">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <div className="w-4 h-4 rounded-full bg-indigo-500/20 flex items-center justify-center text-[10px] text-indigo-400 font-bold">T</div>
                            <span className="font-medium">Narration (Gemini TTS)</span>
                        </div>
                        <span className="bg-zinc-800 px-2 py-0.5 rounded text-xs font-mono text-white">{stats.audioGenerated} Calls</span>
                    </div>
                    <div className="text-xs text-zinc-500 bg-zinc-950/50 p-3 rounded-lg border border-zinc-800/50">
                        <p className="font-semibold text-zinc-400 mb-1">Rate Limits:</p>
                        <p>Shared quota with Gemini Flash text generation. One call is made per scene generated.</p>
                    </div>
                 </div>

                 {/* Visuals Stats */}
                 <div className="space-y-2">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <Film className="w-4 h-4 text-pink-400" />
                            <span className="font-medium">Visuals (Pollinations.ai)</span>
                        </div>
                        <span className="bg-zinc-800 px-2 py-0.5 rounded text-xs font-mono text-white">{stats.imagesGenerated} Calls</span>
                    </div>
                    <div className="text-xs text-zinc-500 bg-zinc-950/50 p-3 rounded-lg border border-zinc-800/50">
                        <p className="font-semibold text-zinc-400 mb-1">Rate Limits:</p>
                        <p>Free, unlimited service. Soft rate limits based on IP address may apply during high traffic.</p>
                    </div>
                 </div>
              </div>

              <div className="p-4 bg-zinc-950 border-t border-zinc-800 text-center">
                  <p className="text-xs text-zinc-500">
                    Stats reset when you refresh the page.
                  </p>
              </div>
           </div>
        </div>
      )}

      <main className="pt-24 pb-12 px-6 max-w-5xl mx-auto">

        {/* API Key Warning */}
        {!isApiKeySet && appState === AppState.IDLE && (
           <div className="mb-8 p-4 bg-yellow-500/10 border border-yellow-500/20 rounded-xl flex items-start gap-3">
             <AlertCircle className="w-5 h-5 text-yellow-500 shrink-0 mt-0.5" />
             <div>
               <h3 className="font-semibold text-yellow-500 text-sm mb-1">API Key Required</h3>
               <p className="text-zinc-400 text-sm">
                 To generate the story script and narration, you need to select a paid Google Cloud Project API key. 
                 <button onClick={handleSelectKey} className="text-yellow-500 hover:underline ml-1">Select Key</button>
               </p>
             </div>
           </div>
        )}

        {/* Input Phase */}
        {appState === AppState.IDLE && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
             <div className="space-y-4 max-w-2xl">
                <h1 className="text-5xl md:text-6xl font-extrabold tracking-tighter text-transparent bg-clip-text bg-gradient-to-b from-white to-white/40">
                  Turn ideas into movies.
                </h1>
                <p className="text-lg text-zinc-400">
                  Enter a prompt, and AI will write the script, voice the characters, and film the scenes.
                </p>
             </div>

             <div className="w-full max-w-md space-y-6">
               {/* Prompt Input */}
               <div className="relative group">
                 <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-xl opacity-75 group-hover:opacity-100 blur transition duration-200"></div>
                 <div className="relative flex bg-black rounded-xl p-1">
                   <input 
                      type="text" 
                      value={topic}
                      onChange={(e) => setTopic(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleGenerateStory()}
                      placeholder="E.g., A cyberpunk detective in 2099..."
                      className="w-full bg-transparent text-white placeholder-zinc-500 px-4 py-3 outline-none"
                   />
                   <button 
                      onClick={handleGenerateStory}
                      disabled={!topic.trim()}
                      className="bg-zinc-900 hover:bg-zinc-800 text-white p-3 rounded-lg transition-colors border border-zinc-800"
                   >
                      <ArrowRight className="w-5 h-5" />
                   </button>
                 </div>
               </div>

               {/* Configuration Section */}
               <div className="bg-zinc-900/50 border border-zinc-800 rounded-xl p-5 space-y-5 backdrop-blur-sm">

                  {/* Duration Selector with Custom Input */}
                  <div className="space-y-2">
                     <div className="flex justify-between items-baseline">
                        <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider">Video Duration</label>
                        <span className="text-xs font-mono text-indigo-400">{duration} seconds</span>
                     </div>
                     <div className="flex flex-wrap gap-2">
                        {[15, 30, 60].map((s) => (
                           <button
                              key={s}
                              onClick={() => setDuration(s)}
                              className={`
                                 flex items-center gap-1.5 px-4 py-2 rounded-lg text-xs font-medium border transition-all
                                 ${duration === s 
                                 ? 'bg-zinc-100 text-black border-zinc-100' 
                                 : 'bg-zinc-950 text-zinc-400 border-zinc-800 hover:border-zinc-700 hover:text-white'
                                 }
                              `}
                           >
                              <Clock className="w-3 h-3" />
                              {s}s
                           </button>
                        ))}
                        <div className={`relative flex items-center bg-zinc-950 border rounded-lg px-3 transition-colors ${duration > 0 && ![15,30,60].includes(duration) ? 'border-indigo-500 ring-1 ring-indigo-500/20' : 'border-zinc-800 focus-within:border-zinc-600'}`}>
                           <span className="text-zinc-500 text-xs mr-2">Custom:</span>
                           <input
                              type="number"
                              min={5}
                              max={300}
                              value={duration}
                              onChange={(e) => {
                                 const val = parseInt(e.target.value);
                                 setDuration(isNaN(val) ? 0 : Math.min(300, Math.max(0, val)));
                              }}
                              className="w-12 bg-transparent text-white text-xs outline-none py-2 font-mono font-medium"
                           />
                           <span className="text-zinc-500 text-xs ml-1">s</span>
                        </div>
                     </div>
                  </div>

                  {/* Estimated API Spending/Usage (Detailed) */}
                  <div className="space-y-4 pt-4 border-t border-zinc-800/50">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2 text-indigo-400">
                            <Calculator className="w-4 h-4" />
                            <span className="text-xs font-bold uppercase tracking-wider">Detailed Estimation</span>
                        </div>
                        <div className="flex items-center gap-1.5 text-zinc-400">
                            <Zap className="w-3.5 h-3.5 text-yellow-500" />
                            <span className="text-xs font-mono">~{estimatedTime}s generation time</span>
                        </div>
                    </div>

                    <div className="space-y-2">
                        {/* Scripting Row */}
                        <div className="grid grid-cols-12 gap-2 text-xs bg-zinc-950/30 p-2 rounded-lg border border-zinc-800/30 items-center">
                            <div className="col-span-4 flex flex-col">
                                <span className="text-zinc-500 font-semibold uppercase text-[10px]">Scripting</span>
                                <span className="text-white font-medium">Gemini 2.5 Flash</span>
                            </div>
                            <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Tier</span>
                                <span className="text-green-400 font-medium">Free Available</span>
                            </div>
                             <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Calls</span>
                                <span className="text-zinc-200">1 Request</span>
                            </div>
                             <div className="col-span-2 text-right text-zinc-500 text-[10px] font-mono">
                                ~5s
                            </div>
                        </div>

                        {/* Narration Row */}
                        <div className="grid grid-cols-12 gap-2 text-xs bg-zinc-950/30 p-2 rounded-lg border border-zinc-800/30 items-center">
                            <div className="col-span-4 flex flex-col">
                                <span className="text-zinc-500 font-semibold uppercase text-[10px]">Narration</span>
                                <span className="text-white font-medium">Gemini TTS</span>
                            </div>
                            <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Tier</span>
                                <span className="text-green-400 font-medium">Free Available</span>
                            </div>
                             <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Calls</span>
                                <span className="text-zinc-200">{estimatedScenes} Requests</span>
                            </div>
                            <div className="col-span-2 text-right text-zinc-500 text-[10px] font-mono">
                                ~3s
                            </div>
                        </div>

                        {/* Visuals Row */}
                        <div className="grid grid-cols-12 gap-2 text-xs bg-zinc-950/30 p-2 rounded-lg border border-zinc-800/30 items-center">
                             <div className="col-span-4 flex flex-col">
                                <span className="text-zinc-500 font-semibold uppercase text-[10px]">Visuals</span>
                                <span className="text-white font-medium">Pollinations (Flux)</span>
                            </div>
                            <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Tier</span>
                                <span className="text-indigo-400 font-medium">Unlimited</span>
                            </div>
                             <div className="col-span-3">
                                <span className="block text-zinc-400 text-[10px]">Calls</span>
                                <span className="text-zinc-200">{estimatedScenes} Requests</span>
                            </div>
                            <div className="col-span-2 text-right text-zinc-500 text-[10px] font-mono">
                                ~{estimatedScenes * 4}s
                            </div>
                        </div>
                    </div>
                  </div>
               </div>
             </div>

             <div className="flex gap-4 text-sm text-zinc-500">
               <span className="flex items-center gap-1"><Sparkles className="w-3 h-3" /> Gemini 2.5 Flash Scripting</span>
               <span className="flex items-center gap-1"><Film className="w-3 h-3" /> Pollinations.ai Visuals</span>
             </div>
          </div>
        )}

        {/* Loading Phase */}
        {(appState === AppState.SCRIPTING || appState === AppState.GENERATING_ASSETS) && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8">
            <div className="relative w-24 h-24">
               <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
               <div 
                  className="absolute inset-0 border-4 border-indigo-500 rounded-full border-t-transparent animate-spin"
               ></div>
               <div className="absolute inset-0 flex items-center justify-center">
                 <Wand2 className="w-8 h-8 text-indigo-400 animate-pulse" />
               </div>
            </div>

            <div className="text-center space-y-2">
              <h2 className="text-2xl font-bold">
                {appState === AppState.SCRIPTING ? 'Writing the Script...' : 'Filming Scenes...'}
              </h2>
              <p className="text-zinc-400">
                {appState === AppState.SCRIPTING 
                  ? `Crafting a ${duration} second story in Kannada...` 
                  : `Generating AI assets: ${Math.round(progress)}%`
                }
              </p>
            </div>

            {appState === AppState.GENERATING_ASSETS && (
              <div className="w-full max-w-md space-y-3">
                 {scenes.map((scene) => (
                    <div key={scene.id} className="flex items-center gap-3 text-sm">
                      <div className={`w-2 h-2 rounded-full ${
                        scene.status === 'complete' ? 'bg-green-500' : 
                        scene.status === 'loading' ? 'bg-yellow-500 animate-pulse' : 
                        scene.status === 'error' ? 'bg-red-500' : 'bg-zinc-700'
                      }`} />
                      <span className={`flex-1 truncate ${scene.status === 'pending' ? 'text-zinc-600' : 'text-zinc-300'}`}>
                        Scene {scene.id + 1}: {scene.narration}
                      </span>
                    </div>
                 ))}
              </div>
            )}
          </div>
        )}

        {/* Editor/Preview Phase */}
        {appState === AppState.PREVIEW && story && (
