                    <div className="bg-zinc-950 rounded-lg border border-zinc-800/50 overflow-hidden">
                       <div className="bg-zinc-900/50 px-4 py-2 border-b border-zinc-800/50 flex justify-between items-center">
                          <span className="text-xs font-mono text-zinc-500">services/geminiService.ts</span>
