import React, { useState, useEffect } from 'react';
import { AppState, Scene, Story, UsageStats } from './types';
import { generateStoryScript, generateNarration, generateCinematicImage } from './services/geminiService';
import { VideoPlayer } from './components/VideoPlayer';
import { Clapperboard, Sparkles, AlertCircle, Film, ArrowRight, Wand2, Clock, Activity, X, Calculator, Zap, Code, Terminal, Layers, Cpu, FileJson, Copy, Check } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [topic, setTopic] = useState('');
  const [duration, setDuration] = useState<number>(30);
  const [story, setStory] = useState<Story | null>(null);
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [progress, setProgress] = useState(0); // 0-100
  const [error, setError] = useState<string | null>(null);
  const [isApiKeySet, setIsApiKeySet] = useState(false);

  // Usage Tracking State
  const [stats, setStats] = useState<UsageStats>({ scriptsGenerated: 0, audioGenerated: 0, imagesGenerated: 0 });
  const [showStats, setShowStats] = useState(false);

  // Documentation/Architecture State
  const [showDocs, setShowDocs] = useState(false);
  const [showPython, setShowPython] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async (): Promise<boolean> => {
    // Check if key is manually set in environment (e.g. .env file)
    if (process.env.API_KEY) {
      setIsApiKeySet(true);
      return true;
    }

    // Check AI Studio platform integration
    const aiStudio = (window as any).aistudio;
    if (aiStudio && await aiStudio.hasSelectedApiKey()) {
      setIsApiKeySet(true);
      return true;
    }

    setIsApiKeySet(false);
    return false;
  };

  const handleSelectKey = async () => {
    const aiStudio = (window as any).aistudio;
    if (aiStudio) {
      try {
        await aiStudio.openSelectKey();
      } catch (e) {
        console.error("Key selection cancelled or failed", e);
      }
      await checkApiKey();
    }
  };

  const handleGenerateStory = async () => {
    if (!topic.trim()) return;

    // Ensure key is available
    const hasKey = await checkApiKey();
    if (!hasKey) {
      await handleSelectKey();
      // Re-check after attempt
      const hasKeyAfterSelect = await checkApiKey();
      if (!hasKeyAfterSelect) return;
    }

    setAppState(AppState.SCRIPTING);
    setError(null);

    try {
      // Pass selected duration to the service
      const script = await generateStoryScript(topic, 'dramatic', duration);

      // Update Stats
      setStats(prev => ({ ...prev, scriptsGenerated: prev.scriptsGenerated + 1 }));

      const initialScenes: Scene[] = script.scenes.map((s, i) => ({
        id: i,
        narration: s.narration,
        visualPrompt: s.visual_description,
        duration: 0,
        status: 'pending'
      }));

      setStory({
        title: script.title,
        scenes: initialScenes,
        musicMood: 'dramatic' // default
      });
      setScenes(initialScenes);

      // Start Asset Generation automatically
      generateAssets(initialScenes);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate story script";
      // Handle the case where the key is invalid or not found (common with some environments)
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("API key not valid")) {
        setIsApiKeySet(false);
        const aiStudio = (window as any).aistudio;
        if (aiStudio) {
            await aiStudio.openSelectKey();
            await checkApiKey();
        }
      }
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  const generateAssets = async (currentScenes: Scene[]) => {
    setAppState(AppState.GENERATING_ASSETS);
    const updatedScenes = [...currentScenes];
    const totalSteps = currentScenes.length * 2; // Audio + Visual per scene
    let completedSteps = 0;

    try {
      // 1. Generate Audio (Parallel) - Uses Gemini
      const audioPromises = updatedScenes.map(async (scene, index) => {
        try {
          const audioUrl = await generateNarration(scene.narration);
          updatedScenes[index].audioUrl = audioUrl;
          updatedScenes[index].status = 'loading'; // audio done, waiting for image

          // Update Stats
          setStats(prev => ({ ...prev, audioGenerated: prev.audioGenerated + 1 }));

        } catch (err) {
          console.error(`Audio failed for scene ${index}`, err);
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
        }
      });

      await Promise.all(audioPromises);

      // 2. Generate Images (Sequential for safety, though Pollinations is free)
      for (let i = 0; i < updatedScenes.length; i++) {
        try {
          const visualUrl = await generateCinematicImage(updatedScenes[i].visualPrompt);
          updatedScenes[i].visualUrl = visualUrl;
          updatedScenes[i].status = 'complete';

          // Update Stats
          setStats(prev => ({ ...prev, imagesGenerated: prev.imagesGenerated + 1 }));

        } catch (err) {
          console.error(`Image failed for scene ${i}`, err);
          updatedScenes[i].status = 'error';
        } finally {
          completedSteps++;
          setProgress((completedSteps / totalSteps) * 100);
          setScenes([...updatedScenes]); // Update UI
        }
      }

      setScenes(updatedScenes);
      setAppState(AppState.PREVIEW);

    } catch (e: any) {
      const errorMessage = e.message || "Failed to generate assets. Please try again.";
      setError(errorMessage);
      setAppState(AppState.IDLE);
    }
  };

  const copyPythonCode = () => {
    navigator.clipboard.writeText(pythonCodeString);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Calculate Estimates
  const estimatedScenes = Math.max(3, Math.ceil(duration / 6));
  // Rough calculation: 5s script + 3s audio batch + (4s per image * numScenes)
  const estimatedTime = 5 + 3 + (estimatedScenes * 4);

  const pythonCodeString = `import os
import time
import json
import textwrap
import requests
import google.generativeai as genai
from moviepy.editor import (
    AudioFileClip, ImageClip, TextClip, CompositeVideoClip, concatenate_videoclips
)

# ---------------------------------------------------------
# CONFIGURATION
# ---------------------------------------------------------
API_KEY = os.getenv("API_KEY")
if not API_KEY:
    raise ValueError("Set API_KEY environment variable")

genai.configure(api_key=API_KEY)
TEMP_DIR = "temp_assets"
os.makedirs(TEMP_DIR, exist_ok=True)

# ---------------------------------------------------------
# 1. ORCHESTRATOR (Gemini 2.5 Flash)
# ---------------------------------------------------------
def generate_script(topic, duration=30):
    print(f"🎬 Generating script for: '{topic}'...")
    num_scenes = max(3, int(duration / 6))
    model = genai.GenerativeModel("gemini-2.5-flash")

    prompt = f"""
    You are a world-class cinematographer. 
    Write a short, engaging, cinematic story about: "{topic}".
    Mood: Dramatic.
    Target Duration: {duration} seconds.
    Structure into exactly {num_scenes} scenes.

    For each scene provide:
    1. 'narration': Voiceover text (English).
    2. 'visual_description': Detailed AI image prompt (Lighting, Camera Angle).

    Return strict JSON: {{ "title": "str", "scenes": [{{ "narration": "str", "visual_description": "str" }}] }}
    """

    response = model.generate_content(prompt, generation_config={"response_mime_type": "application/json"})
    return json.loads(response.text)

# ---------------------------------------------------------
# 2. AUDIO (Gemini TTS)
# ---------------------------------------------------------
def generate_audio(text, index):
    print(f"🎙️ Generating audio for Scene {index + 1}...")
    client = genai.Client(api_key=API_KEY)
    response = client.models.generate_content(
        model="gemini-2.5-flash-preview-tts",
        contents=text,
        config={
            "response_modalities": ["AUDIO"],
            "speech_config": {"voice_config": {"prebuilt_voice_config": {"voice_name": "Fenrir"}}}
        }
    )
    filename = os.path.join(TEMP_DIR, f"scene_{index}.wav")
    for part in response.candidates[0].content.parts:
        if part.inline_data:
            with open(filename, 'wb') as f: f.write(part.inline_data.data)
    return filename

# ---------------------------------------------------------
# 3. VISUALS (Pollinations / Flux)
# ---------------------------------------------------------
def generate_image(prompt, index):
    print(f"🎨 Generating image for Scene {index + 1}...")
    safe_prompt = prompt.replace(" ", "%20")
    # 9:16 Aspect Ratio (720x1280)
    url = f"https://image.pollinations.ai/prompt/Cinematic%20vertical%20{safe_prompt}%20high%20detail?width=720&height=1280&model=flux&nologo=true"
    response = requests.get(url)
    filename = os.path.join(TEMP_DIR, f"scene_{index}.jpg")
    with open(filename, 'wb') as f: f.write(response.content)
    return filename

# ---------------------------------------------------------
# 4. RENDER (MoviePy)
# ---------------------------------------------------------
def main():
    topic = input("Enter story topic: ")
    script = generate_script(topic)
    clips = []

    for i, scene in enumerate(script['scenes']):
        audio_path = generate_audio(scene['narration'], i)
        image_path = generate_image(scene['visual_description'], i)

        # Create Clip
        audio = AudioFileClip(audio_path)
        img = ImageClip(image_path).set_duration(audio.duration + 0.5)

        # Ken Burns (Zoom)
        img = img.resize(lambda t: 1 + 0.04 * t).set_position("center")

        video = CompositeVideoClip([img], size=(720, 1280)).set_audio(audio)
        clips.append(video)

    print("🎞️ Stitching video...")
    final = concatenate_videoclips(clips, method="compose")
    final.write_videofile("output_story.mp4", fps=24, codec='libx264', audio_codec='aac')
    print("✅ Done! Saved as output_story.mp4")

if __name__ == "__main__":
    main()`;

  return (
