                      <div className="relative rounded-md overflow-hidden aspect-video bg-black">
                        {scene.visualUrl ? (
                          <img src={scene.visualUrl} alt="Scene preview" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition-opacity" />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-zinc-700 text-xs">No Visual</div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

           </div>
        )}

        {error && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-red-500/10 border border-red-500 text-red-500 px-6 py-4 rounded-lg backdrop-blur-md shadow-xl flex items-center gap-3 z-50">
             <AlertCircle className="w-5 h-5" />
             <span>{error}</span>
             <button onClick={() => setAppState(AppState.IDLE)} className="ml-4 text-white bg-red-600 hover:bg-red-700 px-3 py-1 rounded text-sm">Dismiss</button>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;
